import{_ as t,o as r,c as a,a7 as n}from"./chunks/framework.BgApuQ2e.js";const o="/images/genie-question/pinit_fg_en_rect_gray_20.png",f=JSON.parse('{"title":"The Genie Question","description":"","frontmatter":{"title":"The Genie Question","titleZh":"神灯精灵之问","date":"2014-09-25T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2014/09/genie-question.html","slug":"genie-question"},"headers":[],"relativePath":"posts/genie-question.md","filePath":"posts/genie-question.md","lastUpdated":1782886257000}'),i={name:"posts/genie-question.md"};function s(p,e,h,l,m,g){return r(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="神灯精灵之问-·-the-genie-question" tabindex="-1">神灯精灵之问 · The Genie Question <a class="header-anchor" href="#神灯精灵之问-·-the-genie-question" aria-label="Permalink to &quot;神灯精灵之问 · The Genie Question&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2014/09/genie-question.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2014/09/genie-question.html</a> · 2014-09-25</p></blockquote><p><a href="https://waitbutwhy.com/2014/07/odd-things-odd-places-intro.html" target="_blank" rel="noreferrer">这次旅行系列</a>的一个关键点在于:我去的这些地方彼此都非常<em>不一样</em>。</p><p>我之所以想挑差异极大的国家,不只是为了观察它们之间的巨大反差——我更好奇的是,它们之间会有什么是<em>共通的</em>。</p><p>因为如果某样东西在俄罗斯、日本、尼日利亚、伊拉克<em>和</em>格陵兰都存在,那它肯定无处不在。所以从这个角度看,一个接一个地拜访这些国家,给了我一个观察人类共同处境的透镜。</p><p>我在这五个地方都发现的一些东西是可以预料的——足球、涂鸦、电视、手机——但更有趣的一个提醒是:在文化这层外壳之下,所有人其实是多么惊人地相似。没有什么比下面这段视频更能说明这一点了。<a href="#footnote-1-2522">1</a></p><p>正如我在系列开头提到的,我打算做的一件事是在每个国家问几十个人同一个问题:「如果你有一个像阿拉丁那样的神灯精灵,可以许三个愿望,你会许什么?」</p><p>我想看看不同地方的人到底<em>渴望</em>什么。</p><p>以下是他们的回答:</p><p><strong>相关文章:</strong></p><p><strong><a href="https://waitbutwhy.com/2014/07/russia-what-you-didnt-know.html" target="_blank" rel="noreferrer">俄罗斯 (Russia)</a></strong></p><p><strong><a href="https://waitbutwhy.com/2014/07/japan-and-how-i-failed-to-figure-it-out.html" target="_blank" rel="noreferrer">日本 (Japan)</a></strong></p><p><strong><a href="https://waitbutwhy.com/2014/08/19-things-learned-nigeria.html" target="_blank" rel="noreferrer">尼日利亚 (Nigeria)</a></strong><a href="#footnote-2-2522">2</a></p><p><strong><a href="https://waitbutwhy.com/2014/09/muhammad-isis-iraqs-full-story.html" target="_blank" rel="noreferrer">伊拉克 (Iraq)</a></strong></p><p><strong><a href="https://waitbutwhy.com/2014/09/but-what-about-greenland.html" target="_blank" rel="noreferrer">格陵兰 (Greenland)</a></strong></p><p>还有一次去的,<strong><a href="https://waitbutwhy.com/2013/09/20-things-i-learned-while-i-was-in.html" target="_blank" rel="noreferrer">朝鲜 (North Korea)</a></strong></p><hr><ol><li><p>请原谅我业余水平的拍摄和剪辑。我不是个手巧的人。<a href="#note-1-2522">↩</a></p></li><li><p>尼日利亚那篇发出来之后,有位读者发起了一个募捐活动,想帮 Femi 支付大学学费并养家(Femi 就是在我去尼日利亚时收留我的那位——他父亲去世后,他不得不辍学去养活一家十口)。WBW 的读者们一共捐了超过 1000 美元,这笔钱本周就会送到 Femi 手里——你可以在视频的 3:22、3:58 和 5:08 看到他)。<a href="#note-2-2522">↩</a></p></li></ol><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2014/09/genie-question.html&amp;description=The%20Genie%20Question" target="_blank" rel="noreferrer"><img src="'+o+'" alt=""></a></p>',20)])])}const _=t(i,[["render",s]]);export{f as __pageData,_ as default};
